External knowledge: 
- Total remaining stock is calculated as the quantity in stock minus the reorder point; 
- Reorder point is the quantity that triggers a reorder; 
- Quantity in stock refers to the quantity of the wire available in the inventory.

sql:
SELECT awg_size
FROM wire_types
WHERE nominal_insulation_thickness > 0.02;

SELECT wire_type_id, COUNT(*) AS total_usage
FROM wire_usage
GROUP BY wire_type_id;

SELECT user_id, COUNT(*) AS request_count
FROM wire_requests
GROUP BY user_id;

SELECT wire_type_id, created_date
FROM wire_types
ORDER BY created_date ASC;

SELECT request_date, status, request_notes
FROM wire_requests
WHERE status = 'pending';

SELECT SUM(quantity_used) AS total_quantity_used
FROM wire_usage
WHERE wire_type_id = 1;

SELECT COUNT(*)
FROM wire_requests
WHERE status = 'pending';

SELECT SUM(quantity_used) AS total_wire_used
FROM wire_usage
WHERE wire_type_id = 0;
